{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier context. A customer-initiated cancellation intersects multiple bounded contexts: order management, dispatch/fulfillment, billing, and courier operations. The cancellation window and permissibility are fundamentally governed by the physical state of the shipment — once a package is in motion, cancellation has real-world costs and may be physically impossible.",
    "bounded_context": "Order Management (primary), with downstream effects on Dispatch, Billing, and Courier Assignment",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A customer's request for a courier to pick up and deliver a package from origin to destination." },
      { "term": "Order Lifecycle", "definition": "The sequence of states an order passes through: PLACED → CONFIRMED → ASSIGNED → PICKED_UP → IN_TRANSIT → DELIVERED. Terminal states also include CANCELLED and FAILED." },
      { "term": "Cancellation", "definition": "A customer-initiated request to terminate an order before it reaches a terminal state (DELIVERED or FAILED). Not the same as a return or a dispute." },
      { "term": "Cancellation Window", "definition": "The set of order states during which cancellation is permitted. Cancellability shrinks as the order progresses through its lifecycle." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after operational costs have been incurred (e.g., courier already dispatched)." },
      { "term": "Assignment", "definition": "The point at which a courier is allocated to fulfill an order. A key inflection point for cancellation cost." },
      { "term": "Pickup", "definition": "The physical event of a courier taking possession of the package. After pickup, the package is in the courier's custody." },
      { "term": "Refund", "definition": "The return of payment to the customer, which may be full or partial depending on when cancellation occurs." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled if it has NOT yet reached a terminal state (DELIVERED, FAILED, or already CANCELLED).",
      "invariant": true,
      "invariant_justification": "A delivered package cannot be un-delivered. A completed or already-cancelled order cannot be cancelled again. This is a physical and state-consistency constraint.",
      "testable_assertion": "Given an order in state DELIVERED, FAILED, or CANCELLED, any cancellation request MUST be rejected with an appropriate error."
    },
    {
      "id": "BR-2",
      "rule": "An order in state PLACED or CONFIRMED (pre-assignment) may be cancelled with a full refund and no cancellation fee.",
      "invariant": false,
      "invariant_justification": "The fee waiver for early cancellation is a business policy decision, not a physical constraint. A VP could introduce an early-cancellation admin fee.",
      "testable_assertion": "Given an order in state PLACED or CONFIRMED, when the customer cancels, the order transitions to CANCELLED and a full refund is issued with zero fees."
    },
    {
      "id": "BR-3",
      "rule": "An order in state ASSIGNED (courier dispatched but package not yet picked up) may be cancelled, but a cancellation fee MAY apply to cover wasted courier effort.",
      "invariant": false,
      "invariant_justification": "Whether a fee applies and its amount is a business policy. The fact that cancellation is still possible is domain-correct since the package has not changed custody.",
      "testable_assertion": "Given an order in state ASSIGNED, when the customer cancels, the order transitions to CANCELLED and the refund amount reflects any applicable cancellation fee."
    },
    {
      "id": "BR-4",
      "rule": "An order in state PICKED_UP or IN_TRANSIT (package in courier custody) MUST NOT be cancellable via self-service. It requires manual intervention or a different process (return/recall).",
      "invariant": true,
      "invariant_justification": "Once the courier has physical custody, cancellation is no longer a simple state change — it requires a physical recall operation. Allowing self-service cancellation here would create an inconsistency between system state and physical reality.",
      "testable_assertion": "Given an order in state PICKED_UP or IN_TRANSIT, a cancellation request MUST be rejected, and the system MUST direct the user toward a return or support escalation flow."
    },
    {
      "id": "BR-5",
      "rule": "Only the customer who placed the order (the order owner) may cancel it.",
      "invariant": true,
      "invariant_justification": "Authorization is a data integrity constraint. Allowing any user to cancel any order would corrupt the trust model.",
      "testable_assertion": "Given a cancellation request from a user who is NOT the order owner, the request MUST be rejected with a 403/authorization error."
    },
    {
      "id": "BR-6",
      "rule": "Cancellation MUST be idempotent. Cancelling an already-cancelled order returns success (or a no-op acknowledgment) without side effects such as duplicate refunds.",
      "invariant": true,
      "invariant_justification": "Duplicate refunds corrupt financial records. Idempotency is a data consistency constraint, not a policy choice.",
      "testable_assertion": "Given an order already in state CANCELLED, a second cancellation request MUST NOT trigger an additional refund or fee, and MUST return a success or already-cancelled response."
    },
    {
      "id": "BR-7",
      "rule": "A cancellation event MUST be recorded as an immutable audit entry with timestamp, actor, prior state, and reason.",
      "invariant": true,
      "invariant_justification": "Audit trail integrity is a compliance and data consistency constraint. Financial events must be traceable.",
      "testable_assertion": "Given a successful cancellation, an audit record MUST exist containing: order_id, cancelled_by, previous_state, cancellation_timestamp, and reason."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An order in state PLACED or CONFIRMED owned by the requesting customer",
      "when": "The customer submits a cancellation request",
      "then": "The order transitions to CANCELLED, a full refund is initiated, no cancellation fee is charged, and a cancellation confirmation is returned to the customer"
    },
    {
      "id": "AC-2",
      "given": "An order in state ASSIGNED owned by the requesting customer",
      "when": "The customer submits a cancellation request",
      "then": "The order transitions to CANCELLED, the courier assignment is released, the applicable cancellation fee (if any) is deducted, and the remaining amount is refunded"
    },
    {
      "id": "AC-3",
      "given": "An order in state PICKED_UP or IN_TRANSIT",
      "when": "The customer submits a cancellation request",
      "then": "The cancellation is rejected with a clear message explaining the order cannot be self-service cancelled at this stage, and the customer is directed to support or the return flow"
    },
    {
      "id": "AC-4",
      "given": "An order in state DELIVERED, FAILED, or CANCELLED",
      "when": "The customer submits a cancellation request",
      "then": "The cancellation is rejected with a message indicating the order is already in a terminal state and cannot be cancelled"
    },
    {
      "id": "AC-5",
      "given": "A cancellation request from a user who does NOT own the order",
      "when": "The request is processed",
      "then": "The request is rejected with an authorization error and no state change occurs"
    },
    {
      "id": "AC-6",
      "given": "An order that has already been cancelled",
      "when": "The customer submits another cancellation request",
      "then": "The system returns a success or already-cancelled acknowledgment without issuing a duplicate refund or recording a duplicate fee"
    },
    {
      "id": "AC-7",
      "given": "Any successful cancellation",
      "when": "The cancellation completes",
      "then": "An immutable audit record is persisted containing order_id, actor, previous_state, timestamp, and reason; and relevant downstream systems (dispatch, billing) are notified"
    },
    {
      "id": "AC-8",
      "given": "An order in state ASSIGNED with a courier en route",
      "when": "The customer cancels the order",
      "then": "The courier is notified of the cancellation in near-real-time so they can stop traveling to the pickup location"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Race condition: customer cancels while the order is transitioning from ASSIGNED to PICKED_UP (courier picks up the package at the exact moment of cancellation)",
      "expected_behavior": "The system MUST use optimistic locking or compare-and-swap on order state. If the state changed to PICKED_UP before the cancellation commits, the cancellation MUST be rejected. The physical state of the package is the source of truth."
    },
    {
      "scenario": "Payment refund fails after order is already marked CANCELLED",
      "expected_behavior": "The order remains in CANCELLED state (do NOT roll back to a previous state — that would be domain-incorrect). The failed refund is flagged for manual resolution. The customer sees 'Cancelled — refund pending' rather than a silent failure."
    },
    {
      "scenario": "Customer cancels during a payment hold or pre-authorization that has not yet been captured",
      "expected_behavior": "The hold/pre-auth is released rather than captured-then-refunded. This avoids unnecessary financial churn and is operationally cleaner."
    },
    {
      "scenario": "Bulk or rapid-fire cancellation requests (potential abuse or automation)",
      "expected_behavior": "Rate limiting is applied per-user. Idempotency prevents duplicate side effects. Anomalous patterns are flagged for fraud review."
    },
    {
      "scenario": "Order has multiple parcels or legs, and only some are cancellable",
      "expected_behavior": "If partial cancellation is not supported, the entire order cancellation is rejected with a message explaining which legs are past the cancellation window. If partial cancellation IS supported, only eligible legs are cancelled and the order total is adjusted accordingly. (AMBIGUITY — see escalations.)"
    },
    {
      "scenario": "Courier has already incurred tolls, fuel, or other non-recoverable costs before cancellation at ASSIGNED state",
      "expected_behavior": "The cancellation fee policy must account for actual incurred costs. The system should capture the cost basis at time of cancellation for accurate fee calculation."
    },
    {
      "scenario": "Customer cancels an order that was placed with a promotional discount or voucher",
      "expected_behavior": "Refund policy must define whether the voucher/discount is reinstated or consumed. This is a business policy decision that must be explicitly defined. (AMBIGUITY — see escalations.)"
    },
    {
      "scenario": "System outage prevents state transition — customer thinks they cancelled but the write failed",
      "expected_behavior": "Cancellation must be confirmed only AFTER the state transition is durably persisted. The response to the customer must not be sent until persistence is confirmed. If persistence fails, the customer is told the cancellation could not be processed and to retry."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly affects revenue (lost delivery fee), cost (wasted courier time if post-assignment), and refund processing costs. A poorly designed cancellation window either loses money (too generous) or loses customers (too restrictive). Cancellation fee policy is a key lever.",
    "operational": "Courier dispatch must react in near-real-time to cancellations to avoid wasted trips. Late notifications to couriers erode courier trust and increase operational cost. Audit and refund reconciliation add back-office load.",
    "user": "Cancellation is a trust-building feature. Customers expect to cancel easily before a courier is involved. Blocking cancellation too early (e.g., at CONFIRMED) will generate support tickets and churn. Allowing it too late creates operational chaos.",
    "risk": "Key risks: (1) race conditions between cancellation and pickup causing physical/digital state mismatch, (2) refund fraud via repeated cancellations, (3) missing audit trail creating compliance exposure, (4) courier dissatisfaction from late cancellation notifications.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Gain self-service cancellation capability. Satisfaction depends on clear communication of cancellation windows and refund timelines." },
      { "group": "Couriers", "impact": "Must receive timely cancellation notifications. Late cancellations after dispatch waste their time and income. Cancellation fee policy partially compensates this." },
      { "group": "Finance/Billing", "impact": "Must handle refund processing, cancellation fee accounting, and voucher reinstatement logic. Reconciliation complexity increases." },
      { "group": "Customer Support", "impact": "Post-pickup cancellation requests will be routed to support. They need clear escalation procedures and authority to handle edge cases." },
      { "group": "Product/Growth", "impact": "Cancellation rate becomes a new metric to monitor. High cancellation rates may indicate UX or pricing issues upstream." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is a single sentence with no detail on order lifecycle states, cancellation fee policy, refund rules, multi-parcel handling, or promotional/voucher treatment. I have applied standard logistics domain knowledge to infer a reasonable order lifecycle and cancellation model, but multiple critical business decisions are undefined. The spec quality is very low — almost every business rule I defined required assumptions.",
    "high_confidence_areas": [
      "Terminal states (DELIVERED, FAILED, CANCELLED) must reject cancellation — this is a physical invariant",
      "Authorization: only order owner can cancel — universal security constraint",
      "Idempotency of cancellation — standard for financial operations",
      "Audit trail requirement — standard compliance need"
    ],
    "low_confidence_areas": [
      "Exact order lifecycle states used in THIS system (assumed standard logistics states)",
      "Cancellation fee policy and amounts at ASSIGNED state",
      "Whether post-pickup cancellation should be fully blocked or routed to support",
      "Multi-parcel / multi-leg order handling",
      "Voucher/promo reinstatement policy on cancellation",
      "Refund timeline SLAs"
    ],
    "assumptions": [
      "Order lifecycle follows: PLACED → CONFIRMED → ASSIGNED → PICKED_UP → IN_TRANSIT → DELIVERED",
      "Self-service cancellation is the scope; admin/support cancellation is a separate feature",
      "Payment has been collected or pre-authorized at time of order placement",
      "Single-parcel orders are the primary use case",
      "Courier notification infrastructure already exists"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states exist or which are cancellable. 'Cancel their order' could mean anything from free cancellation at any point to a narrow pre-dispatch window. The cancellation window is THE critical business decision and it is entirely undefined.",
      "affected_stakeholders": ["Customers", "Couriers", "Finance"],
      "options": [
        "A: Allow cancellation only before courier assignment (most conservative, lowest operational cost)",
        "B: Allow cancellation up to pickup with a fee after assignment (balanced approach, assumed in this analysis)",
        "C: Allow cancellation at any point including in-transit with escalating fees (most customer-friendly, highest operational complexity)"
      ],
      "recommendation": "Option B — standard in the industry. But this MUST be confirmed by the PM with explicit state-by-state cancellation rules."
    },
    {
      "type": "ambiguity",
      "description": "Cancellation fee policy is undefined. How much? Flat fee or percentage? Does it vary by distance the courier has already traveled? Who absorbs the cost — the platform or the customer?",
      "affected_stakeholders": ["Customers", "Couriers", "Finance"],
      "options": [
        "A: No cancellation fee at any stage",
        "B: Flat cancellation fee after courier assignment",
        "C: Variable fee based on courier's incurred costs"
      ],
      "recommendation": "Option B for simplicity at launch, with Option C as a future iteration. PM and Finance must define the amount."
    },
    {
      "type": "ambiguity",
      "description": "Refund mechanism and timeline are undefined. Instant refund? 3-5 business days? Store credit vs original payment method? What happens to promotional vouchers?",
      "affected_stakeholders": ["Customers", "Finance"],
      "options": [
        "A: Instant refund to original payment method, voucher reinstated",
        "B: Refund within N business days, voucher consumed",
        "C: Refund as store credit"
      ],
      "recommendation": "Option A is the customer-friendly default, but Finance must confirm feasibility and voucher policy."
    },
    {
      "type": "missing_context",
      "description": "No information on whether the system supports multi-parcel or multi-leg orders. If it does, partial cancellation semantics are entirely undefined.",
      "affected_stakeholders": ["Customers", "Product", "Engineering"],
      "options": [
        "A: Only full-order cancellation supported",
        "B: Partial cancellation of individual parcels/legs"
      ],
      "recommendation": "Start with Option A (full-order only) and scope partial cancellation as a separate feature if needed."
    }
  ],

  "rejection_reasons": []
}

